"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";

export default function PurchaseOrdersPage() {
  const router = useRouter();
  const [orders, setOrders] = useState<any[]>([]);
  const [showCreateModal, setShowCreateModal] = useState(false);
  const [vendor, setVendor] = useState("");
  const [expectedDate, setExpectedDate] = useState("");
  const [note, setNote] = useState("");
  const [items, setItems] = useState<{item_id: string, item_name: string, quantity: number, unit: string}[]>([]);
  const [loading, setLoading] = useState(false);
  const [suggestLoading, setSuggestLoading] = useState(false);

  const fetchOrders = async () => {
    try {
      const res = await fetch('/api/purchase-orders');
      if (res.ok) {
        setOrders(await res.json());
      }
    } catch (e) {
      console.error(e);
    }
  };

  useEffect(() => {
    fetchOrders();
  }, []);

  const loadSuggestions = async () => {
    setSuggestLoading(true);
    try {
      const res = await fetch(`/api/purchase-orders/suggest${vendor ? `?vendor=${vendor}` : ''}`);
      if (res.ok) {
        const data = await res.json();
        const suggestedItems = data.map((d: any) => ({
          item_id: d.item_id,
          item_name: d.name,
          quantity: d.suggested_order_qty,
          unit: d.unit
        }));
        setItems(suggestedItems);
        if (!vendor && data.length > 0) {
          setVendor(data[0].vendor);
        }
      }
    } catch (e) {
      console.error(e);
    } finally {
      setSuggestLoading(false);
    }
  };

  const handleCreate = async () => {
    setLoading(true);
    try {
      const res = await fetch('/api/purchase-orders', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          vendor,
          expected_date: expectedDate,
          note,
          items
        })
      });

      if (res.ok) {
        setShowCreateModal(false);
        setVendor("");
        setExpectedDate("");
        setNote("");
        setItems([]);
        fetchOrders();
      } else {
        alert("Failed to create PO");
      }
    } catch (e) {
      console.error(e);
      alert("Error creating PO");
    } finally {
      setLoading(false);
    }
  };

  const addItemRow = () => {
    setItems([...items, { item_id: "", item_name: "", quantity: 1, unit: "box" }]);
  };

  const updateItem = (index: number, field: string, value: any) => {
    const newItems = [...items];
    newItems[index] = { ...newItems[index], [field]: value };
    setItems(newItems);
  };

  const removeItem = (index: number) => {
    setItems(items.filter((_, i) => i !== index));
  };

  return (
    <div className="p-6 max-w-7xl mx-auto">
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-bold">Purchase Orders (สั่งซื้อน้ำยา)</h1>
        <div className="flex gap-2">
          <button 
            onClick={() => router.push('/orders/tracking')}
            className="px-4 py-2 bg-blue-100 text-blue-700 rounded hover:bg-blue-200"
          >
            🚚 ติดตามพัสดุ
          </button>
          <button 
            onClick={() => setShowCreateModal(true)}
            className="px-4 py-2 bg-indigo-600 text-white rounded hover:bg-indigo-700"
          >
            + สร้างใบสั่งซื้อ
          </button>
        </div>
      </div>

      <div className="bg-white rounded-lg shadow overflow-hidden">
        <table className="min-w-full divide-y divide-gray-200">
          <thead className="bg-gray-50">
            <tr>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">PO Number</th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Vendor</th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Status</th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Items</th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Date</th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Action</th>
            </tr>
          </thead>
          <tbody className="bg-white divide-y divide-gray-200">
            {orders.map(po => (
              <tr key={po.id} className="hover:bg-gray-50">
                <td className="px-6 py-4 font-medium">{po.po_number}</td>
                <td className="px-6 py-4">{po.vendor}</td>
                <td className="px-6 py-4">
                  <span className={`px-2 py-1 rounded text-xs font-bold ${
                    po.status === 'SUBMITTED' ? 'bg-yellow-100 text-yellow-800' :
                    po.status === 'CONFIRMED' ? 'bg-blue-100 text-blue-800' :
                    po.status === 'SHIPPED' ? 'bg-purple-100 text-purple-800' :
                    po.status === 'RECEIVED' ? 'bg-green-100 text-green-800' :
                    'bg-gray-100 text-gray-800'
                  }`}>
                    {po.status}
                  </span>
                </td>
                <td className="px-6 py-4 text-sm text-gray-500">
                  {po.items?.length || 0} รายการ
                </td>
                <td className="px-6 py-4 text-sm text-gray-500">
                  {new Date(po.created_at).toLocaleDateString()}
                </td>
                <td className="px-6 py-4 text-sm font-medium">
                  <button 
                    onClick={() => router.push(`/orders/${po.id}`)}
                    className="text-indigo-600 hover:text-indigo-900"
                  >
                    ดูรายละเอียด
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {showCreateModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50">
          <div className="bg-white rounded-lg p-6 w-full max-w-4xl max-h-[90vh] overflow-y-auto">
            <div className="flex justify-between items-center mb-4">
              <h2 className="text-xl font-bold">สร้างใบสั่งซื้อ (Create PO)</h2>
              <button onClick={() => setShowCreateModal(false)} className="text-gray-500 hover:text-gray-700">✕</button>
            </div>

            <div className="grid grid-cols-2 gap-4 mb-6">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Vendor (บริษัท)*</label>
                <input 
                  type="text" 
                  value={vendor} 
                  onChange={e => setVendor(e.target.value)}
                  className="w-full border rounded p-2"
                  placeholder="เช่น DKSH"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Expected Date (วันที่คาดว่าจะส่ง)</label>
                <input 
                  type="date" 
                  value={expectedDate} 
                  onChange={e => setExpectedDate(e.target.value)}
                  className="w-full border rounded p-2"
                />
              </div>
            </div>

            <div className="mb-4 flex justify-between items-center">
              <h3 className="font-bold">รายการน้ำยา</h3>
              <div className="flex gap-2">
                <button 
                  onClick={loadSuggestions}
                  disabled={suggestLoading}
                  className="px-3 py-1 bg-yellow-100 text-yellow-800 rounded text-sm hover:bg-yellow-200"
                >
                  {suggestLoading ? 'Loading...' : '🤖 แนะนำอัตโนมัติ (จาก Min Stock)'}
                </button>
                <button 
                  onClick={addItemRow}
                  className="px-3 py-1 bg-gray-100 text-gray-800 rounded text-sm hover:bg-gray-200"
                >
                  + เพิ่มแถว
                </button>
              </div>
            </div>

            {items.map((item, index) => (
              <div key={index} className="flex gap-2 mb-2 items-center">
                <input 
                  placeholder="Item ID" 
                  value={item.item_id}
                  onChange={e => updateItem(index, 'item_id', e.target.value)}
                  className="border rounded p-2 w-1/4"
                />
                <input 
                  placeholder="ชื่อน้ำยา" 
                  value={item.item_name}
                  onChange={e => updateItem(index, 'item_name', e.target.value)}
                  className="border rounded p-2 flex-1"
                />
                <input 
                  type="number" 
                  placeholder="จำนวน" 
                  value={item.quantity}
                  onChange={e => updateItem(index, 'quantity', parseInt(e.target.value))}
                  className="border rounded p-2 w-24"
                />
                <input 
                  placeholder="หน่วย" 
                  value={item.unit}
                  onChange={e => updateItem(index, 'unit', e.target.value)}
                  className="border rounded p-2 w-24"
                />
                <button onClick={() => removeItem(index)} className="text-red-500 hover:text-red-700 p-2">✕</button>
              </div>
            ))}

            {items.length === 0 && (
              <div className="text-center py-8 text-gray-500 bg-gray-50 rounded border border-dashed">
                ยังไม่มีรายการน้ำยา กดปุ่ม + เพิ่มแถว หรือ แนะนำอัตโนมัติ
              </div>
            )}

            <div className="mt-6 mb-4">
              <label className="block text-sm font-medium text-gray-700 mb-1">หมายเหตุเพิ่มเติม</label>
              <textarea 
                value={note} 
                onChange={e => setNote(e.target.value)}
                className="w-full border rounded p-2"
                rows={2}
              />
            </div>

            <div className="flex justify-end gap-2 mt-6 border-t pt-4">
              <button 
                onClick={() => setShowCreateModal(false)}
                className="px-4 py-2 border rounded text-gray-600 hover:bg-gray-50"
              >
                ยกเลิก
              </button>
              <button 
                onClick={handleCreate}
                disabled={loading || items.length === 0 || !vendor}
                className="px-4 py-2 bg-indigo-600 text-white rounded hover:bg-indigo-700 disabled:opacity-50"
              >
                {loading ? 'กำลังบันทึก...' : 'บันทึกและส่ง PO ไปยัง Vendor'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";

export default function TrackingBoardPage() {
  const router = useRouter();
  const [shipments, setShipments] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  const fetchShipments = async () => {
    try {
      // Note: Admin/Manager view fetches all, we should use a specific tracking endpoint
      // but for simplicity we reuse the vendor shipments endpoint which returns all for admins.
      const res = await fetch('/api/vendor/shipments');
      if (res.ok) {
        setShipments(await res.json());
      }
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchShipments();
  }, []);

  const columns = [
    { id: 'In Transit', title: '🚚 กำลังจัดส่ง (In Transit)' },
    { id: 'Received', title: '✅ รับของแล้ว (Received)' },
    { id: 'Cancelled', title: '❌ ยกเลิก (Cancelled)' }
  ];

  if (loading) return <div className="p-6">Loading tracking board...</div>;

  return (
    <div className="p-6 h-screen flex flex-col bg-gray-50">
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-bold">📦 Shipment Tracking Board</h1>
        <button onClick={() => router.push('/orders')} className="text-indigo-600">← กลับไปหน้าระบบสั่งซื้อ</button>
      </div>

      <div className="flex-1 flex gap-6 overflow-x-auto pb-4">
        {columns.map(col => {
          const colShipments = shipments.filter(s => s.status === col.id);
          return (
            <div key={col.id} className="w-80 flex-shrink-0 bg-gray-200 rounded-lg p-4 flex flex-col max-h-full">
              <div className="flex justify-between items-center mb-4 px-1">
                <h3 className="font-bold text-gray-700">{col.title}</h3>
                <span className="bg-gray-300 text-gray-700 text-xs py-1 px-2 rounded-full font-bold">
                  {colShipments.length}
                </span>
              </div>

              <div className="flex-1 overflow-y-auto space-y-3 pr-1">
                {colShipments.map(s => (
                  <div key={s.id} className="bg-white p-4 rounded shadow-sm border-l-4 border-indigo-500 hover:shadow-md transition">
                    <div className="flex justify-between items-start mb-2">
                      <span className="text-xs font-bold bg-indigo-100 text-indigo-800 px-2 py-1 rounded">
                        {s.reference_no}
                      </span>
                      <span className="text-xs text-gray-500">{new Date(s.created_at).toLocaleDateString()}</span>
                    </div>
                    <h4 className="font-bold text-sm mb-1 line-clamp-1" title={s.reagent_name}>{s.reagent_name}</h4>
                    <p className="text-xs text-gray-600 mb-2">Vendor: {s.vendor}</p>
                    <div className="flex justify-between items-center text-sm">
                      <span className="font-medium text-gray-800">{s.quantity} {s.unit}</span>
                      {s.po_number && (
                        <span 
                          onClick={() => router.push(`/orders/${s.po_number}`)}
                          className="text-indigo-600 cursor-pointer hover:underline text-xs"
                        >
                          {s.po_number}
                        </span>
                      )}
                    </div>
                    {s.tracking_no && (
                      <div className="mt-3 pt-3 border-t text-xs">
                        <span className="text-gray-500">{s.tracking_provider}:</span> <span className="font-bold">{s.tracking_no}</span>
                      </div>
                    )}
                  </div>
                ))}
                {colShipments.length === 0 && (
                  <div className="text-center p-4 text-gray-400 text-sm border-2 border-dashed border-gray-300 rounded">
                    ไม่มีรายการ
                  </div>
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

'use client';

import { useState, useEffect, useCallback, useMemo } from 'react';
import { apiClient, Reagent } from '@/lib/api-client';
import { processAnyBarcode } from '@/lib/barcode-parser';
import QRScanner from '@/components/qr-scanner';
import { 
  PackagePlus, 
  Camera, 
  Search, 
  Trash2, 
  Loader2, 
  CheckCircle,
  XCircle,
  AlertCircle
} from 'lucide-react';

interface CartItem {
  itemId: string;
  name: string;
  lotNo: string;
  expDate: string;
  qty: number;
  unit: string;
}

export default function ReceivePage() {
  const [reagents, setReagents] = useState<Reagent[]>([]);
  const [patterns, setPatterns] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [scanMode, setScanMode] = useState(false);
  const [search, setSearch] = useState('');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [feedback, setFeedback] = useState<{ type: 'success' | 'error', msg: string } | null>(null);
  const [showResults, setShowResults] = useState(false);

  // Load reagents for lookup
  useEffect(() => {
    Promise.all([
      apiClient.getDashboard(),
      apiClient.getBarcodePatterns()
    ]).then(([reagentsData, patternsData]) => {
      setReagents(reagentsData);
      setPatterns(patternsData);
      setLoading(false);
    }).catch(err => {
      console.error(err);
      setLoading(false);
    });
  }, []);

  const addToCart = (match: Reagent, lot: string = '', exp: string = '') => {
    const newItem: CartItem = {
      itemId: match.itemId,
      name: match.name,
      lotNo: lot,
      expDate: exp,
      qty: 1,
      unit: match.unit
    };

    setCart(prev => {
      const existing = prev.find(i => i.itemId === newItem.itemId && i.lotNo === newItem.lotNo);
      if (existing) {
        return prev.map(i => i === existing ? { ...i, qty: i.qty + 1 } : i);
      }
      return [newItem, ...prev];
    });

    setSearch('');
    setShowResults(false);
    setFeedback({ type: 'success', msg: `เพิ่ม ${match.name} ลงตะกร้าแล้ว` });
  };

  const handleScan = useCallback((decodedText: string) => {
    const data = processAnyBarcode(decodedText, patterns);
    if (!data) return;

    // Standardize GTIN for lookup (remove leading zeros)
    const cleanGtin = data.gtin.replace(/^0+/, '');
    const cleanRaw = data.rawString.replace(/^0+/, '');

    // Lookup item by GTIN or ItemID
    const match = reagents.find(r => {
      const dbBarcode = r.qrCode?.replace(/^0+/, '') || '';
      const dbItemId = r.itemId.replace(/^0+/, '');
      
      return (
        dbItemId.toLowerCase() === cleanGtin.toLowerCase() || 
        dbBarcode.toLowerCase() === cleanGtin.toLowerCase() ||
        dbItemId.toLowerCase() === cleanRaw.toLowerCase()
      );
    });

    if (match) {
      addToCart(match, data.lot === 'NEED_MANUAL_INPUT' ? '' : data.lot, data.expDate === 'NEED_MANUAL_INPUT' ? '' : data.expDate);
      setScanMode(false);
    } else {
      setFeedback({ type: 'error', msg: 'ไม่พบข้อมูลน้ำยานี้ในระบบ Master Data' });
      setScanMode(false);
    }
  }, [reagents, patterns]);

  const filteredResults = useMemo(() => {
    if (!search.trim()) return [];
    return reagents.filter(r => 
      r.name.toLowerCase().includes(search.toLowerCase()) || 
      r.itemId.toLowerCase().includes(search.toLowerCase())
    ).slice(0, 5);
  }, [search, reagents]);

  const handleManualAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (filteredResults.length === 1) {
      addToCart(filteredResults[0]);
    } else {
      handleScan(search);
    }
  };

  const removeFromCart = (index: number) => {
    setCart(prev => prev.filter((_, i) => i !== index));
  };

  const updateQty = (index: number, newQty: string) => {
    const val = parseInt(newQty) || 0;
    setCart(prev => prev.map((item, i) => i === index ? { ...item, qty: val } : item));
  };

  const updateLotNo = (index: number, newLot: string) => {
    setCart(prev => prev.map((item, i) => i === index ? { ...item, lotNo: newLot } : item));
  };

  const updateExpDate = (index: number, newExp: string) => {
    setCart(prev => prev.map((item, i) => i === index ? { ...item, expDate: newExp } : item));
  };

  const handleSubmit = async () => {
    // Filter out items with 0 or negative quantity
    const validItems = cart.filter(item => item.qty > 0);
    
    if (validItems.length === 0) {
      setFeedback({ type: 'error', msg: 'กรุณาระบุจำนวนที่ต้องการรับเข้า (ต้องมากกว่า 0)' });
      return;
    }

    setSubmitting(true);
    try {
      await apiClient.receiveBatch(validItems);
      setFeedback({ type: 'success', msg: 'บันทึกรายการรับน้ำยาเข้าคลังเรียบร้อยแล้ว' });
      setCart([]);
      } catch (err: unknown) {
      const error = err as { response?: { data?: { error?: string } }, message: string };
      setFeedback({ type: 'error', msg: 'เกิดข้อผิดพลาด: ' + (error.response?.data?.error || error.message) });
      } finally {
      setSubmitting(false);
      }
  };

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center h-96 gap-4">
        <Loader2 className="animate-spin text-blue-600" size={48} />
        <p className="text-gray-500 animate-pulse">กำลังโหลดข้อมูลฐานน้ำยา...</p>
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500 max-w-2xl mx-auto pb-24">
      {/* Header */}
      <div className="flex flex-col gap-2">
        <div className="flex items-center gap-3">
          <div className="w-12 h-12 bg-green-50 text-green-600 rounded-2xl flex items-center justify-center">
            <PackagePlus size={28} />
          </div>
          <h1 className="text-3xl font-bold tracking-tight text-gray-900">รับเข้าคลังหลัก</h1>
        </div>
        <p className="text-gray-500 text-sm">แสกนบาร์โค้ด GS1 หรือพิมพ์รหัสเพื่อเพิ่มลงตะกร้า</p>
      </div>

      {/* Feedback Toast-like */}
      {feedback && (
        <div className={`p-4 rounded-xl flex items-center gap-3 animate-in slide-in-from-top-4 duration-300 ${
          feedback.type === 'success' ? 'bg-green-50 text-green-700 border border-green-100' : 'bg-red-50 text-red-700 border border-red-100'
        }`}>
          {feedback.type === 'success' ? <CheckCircle size={20} /> : <XCircle size={20} />}
          <p className="text-sm font-bold flex-1">{feedback.msg}</p>
          <button onClick={() => setFeedback(null)}><AlertCircle size={16} className="opacity-50" /></button>
        </div>
      )}

      {/* Action Area */}
      <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm space-y-4">
        <button 
          onClick={() => setScanMode(true)}
          className="w-full bg-gray-900 text-white py-4 rounded-2xl font-bold flex items-center justify-center gap-2 hover:bg-gray-800 transition-all active:scale-[0.98] shadow-lg shadow-gray-200"
        >
          <Camera size={20} />
          เปิดกล้องแสกน Barcode
        </button>

        <div className="relative flex items-center">
          <div className="flex-1 border-t border-gray-100"></div>
          <span className="px-4 text-[10px] font-bold text-gray-400 uppercase tracking-widest">หรือพิมพ์รหัส</span>
          <div className="flex-1 border-t border-gray-100"></div>
        </div>

        <form onSubmit={handleManualAdd} className="flex gap-2">
          <div className="relative flex-1">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
            <input 
              type="text"
              value={search}
              onChange={(e) => {
                setSearch(e.target.value);
                setShowResults(true);
              }}
              onFocus={() => setShowResults(true)}
              placeholder="รหัสน้ำยา หรือ บาร์โค้ด..."
              className="w-full pl-11 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl text-sm focus:ring-2 focus:ring-blue-500 outline-none transition-all"
            />
            
            {/* Autocomplete Results */}
            {showResults && filteredResults.length > 0 && (
              <div className="absolute z-10 w-full mt-2 bg-white border border-gray-100 rounded-2xl shadow-xl overflow-hidden animate-in fade-in zoom-in-95 duration-200">
                {filteredResults.map(item => (
                  <button
                    key={item.itemId}
                    type="button"
                    onClick={() => addToCart(item)}
                    className="w-full text-left px-4 py-3 hover:bg-gray-50 flex flex-col border-b border-gray-50 last:border-none"
                  >
                    <span className="text-sm font-bold text-gray-900">{item.name}</span>
                    <span className="text-[10px] font-bold text-gray-400 uppercase">ID: {item.itemId}</span>
                  </button>
                ))}
              </div>
            )}
            
            {/* Click away listener for mobile/desktop */}
            {showResults && (
              <div 
                className="fixed inset-0 z-0" 
                onClick={() => setShowResults(false)}
              />
            )}
          </div>
          <button type="submit" className="bg-blue-50 text-blue-600 px-6 rounded-xl font-bold text-sm hover:bg-blue-100 transition-colors relative z-10">
            เพิ่ม
          </button>
        </form>
      </div>

      {/* Cart Area */}
      <div className="space-y-4">
        <div className="flex items-center justify-between px-2">
          <h2 className="font-bold text-gray-800 flex items-center gap-2">
            รายการในตะกร้า 
            <span className="bg-gray-100 text-gray-600 px-2 py-0.5 rounded-full text-[10px]">{cart.length}</span>
          </h2>
          {cart.length > 0 && (
            <button onClick={() => setCart([])} className="text-xs font-bold text-red-500 uppercase tracking-widest">ล้างตะกร้า</button>
          )}
        </div>

        {cart.length === 0 ? (
          <div className="bg-gray-50/50 border-2 border-dashed border-gray-100 rounded-3xl p-12 text-center">
            <PackagePlus className="mx-auto text-gray-200 mb-4" size={48} />
            <p className="text-gray-400 text-sm">ยังไม่มีรายการในตะกร้า<br/>เริ่มแสกนเพื่อทำรายการรับเข้า</p>
          </div>
        ) : (
          <div className="space-y-3">
            {cart.map((item, index) => (
              <div key={`${item.itemId}-${item.lotNo}-${index}`} className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm flex items-center gap-4 animate-in fade-in slide-in-from-right-4 duration-300">
                <div className="flex-1 min-w-0">
                  <h3 className="font-bold text-gray-900 truncate">{item.name}</h3>
                  <div className="flex flex-wrap gap-x-3 gap-y-2 mt-2 text-[11px] font-medium text-gray-500">
                    <span className="bg-blue-50 text-blue-600 px-1.5 py-0.5 rounded flex items-center">ID: {item.itemId}</span>
                    <div className="flex items-center gap-1">
                      <span className="bg-gray-50 px-1.5 py-0.5 rounded font-mono">Lot:</span>
                      <input 
                        type="text" 
                        value={item.lotNo} 
                        onChange={e => updateLotNo(index, e.target.value)}
                        placeholder="ระบุ Lot"
                        className="border border-gray-200 rounded px-1.5 py-0.5 text-xs outline-none focus:ring-1 focus:ring-blue-500 w-24"
                      />
                    </div>
                    <div className="flex items-center gap-1">
                      <span className="bg-gray-50 px-1.5 py-0.5 rounded">EXP:</span>
                      <input 
                        type="date" 
                        value={item.expDate} 
                        onChange={e => updateExpDate(index, e.target.value)}
                        className="border border-gray-200 rounded px-1.5 py-0.5 text-xs outline-none focus:ring-1 focus:ring-blue-500"
                      />
                    </div>
                  </div>
                </div>
                
                <div className="flex items-center gap-3">
                  <div className="relative">
                    <input 
                      type="number"
                      value={item.qty}
                      onChange={(e) => updateQty(index, e.target.value)}
                      className="w-16 text-center font-bold bg-gray-50 border border-gray-100 rounded-lg py-1.5 text-blue-600 outline-none focus:ring-2 focus:ring-blue-500"
                    />
                    <span className="absolute -top-5 left-1/2 -translate-x-1/2 text-[9px] font-bold text-gray-400 uppercase whitespace-nowrap">{item.unit}</span>
                  </div>
                  <button 
                    onClick={() => removeFromCart(index)}
                    className="p-2 text-gray-300 hover:text-red-500 transition-colors"
                  >
                    <Trash2 size={18} />
                  </button>
                </div>
              </div>
            ))}

            <div className="pt-4 px-2">
              <button 
                onClick={handleSubmit}
                disabled={submitting}
                className="w-full bg-green-600 text-white py-4 rounded-2xl font-bold flex items-center justify-center gap-2 hover:bg-green-700 transition-all active:scale-[0.98] shadow-lg shadow-green-100 disabled:opacity-50"
              >
                {submitting ? <Loader2 className="animate-spin" size={20} /> : <CheckCircle size={20} />}
                ยืนยันการรับเข้า {cart.length} รายการ
              </button>
            </div>
          </div>
        )}
      </div>

      {/* Scanner Modal */}
      {scanMode && (
        <QRScanner 
          onScan={handleScan} 
          onClose={() => setScanMode(false)} 
        />
      )}
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { apiClient, BarcodePattern } from '@/lib/api-client';
import { Trash2, Plus, Loader2, CheckCircle, Save, Camera, X, AlertCircle } from 'lucide-react';
import QRScanner from '@/components/qr-scanner';

export default function BarcodeSettingsPage() {
  const [patterns, setPatterns] = useState<BarcodePattern[]>([]);
  const [loading, setLoading] = useState(true);
  const [showScanner, setShowScanner] = useState(false);

  const [name, setName] = useState('');
  const [regexPattern, setRegexPattern] = useState('');
  const [itemIdGroup, setItemIdGroup] = useState<number | ''>('');
  const [lotNoGroup, setLotNoGroup] = useState<number | ''>('');
  const [expDateGroup, setExpDateGroup] = useState<number | ''>('');

  const [testString, setTestString] = useState('');
  const [testResult, setTestResult] = useState<{ match: boolean, item?: string, lot?: string, exp?: string } | null>(null);
  const [isGS1Warning, setIsGS1Warning] = useState(false);

  const [saving, setSaving] = useState(false);

  // Assistant Mode States
  const [assistantMode, setAssistantMode] = useState(false);
  const [selection, setSelection] = useState<{ start: number, end: number } | null>(null);
  const [mapping, setMapping] = useState<{ item?: [number, number], lot?: [number, number], exp?: [number, number] }>({});

  const loadPatterns = async () => {
    try {
      const data = await apiClient.getBarcodePatterns();
      setPatterns(data);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadPatterns();
  }, []);

  const generateRegexFromMapping = () => {
    if (!testString) return;

    // Sort mapped ranges to build positional regex
    const points: { pos: number, type: 'item' | 'lot' | 'exp' | 'skip', len: number }[] = [];

    if (mapping.item) points.push({ pos: mapping.item[0], type: 'item', len: mapping.item[1] - mapping.item[0] + 1 });
    if (mapping.lot) points.push({ pos: mapping.lot[0], type: 'lot', len: mapping.lot[1] - mapping.lot[0] + 1 });
    if (mapping.exp) points.push({ pos: mapping.exp[0], type: 'exp', len: mapping.exp[1] - mapping.exp[0] + 1 });

    points.sort((a, b) => a.pos - b.pos);

    let regex = '^';
    let currentPos = 0;
    let groupIdx = 1;
    let newItemIdx = 0, newLotIdx = 0, newExpIdx = 0;

    points.forEach(p => {
      if (p.pos > currentPos) {
        regex += `.{${p.pos - currentPos}}`;
      }
      regex += `(.{${p.len}})`;
      if (p.type === 'item') newItemIdx = groupIdx;
      if (p.type === 'lot') newLotIdx = groupIdx;
      if (p.type === 'exp') newExpIdx = groupIdx;

      currentPos = p.pos + p.len;
      groupIdx++;
    });

    regex += '.*$';

    setRegexPattern(regex);
    setItemIdGroup(newItemIdx || '');
    setLotNoGroup(newLotIdx || '');
    setExpDateGroup(newExpIdx || '');
  };

  useEffect(() => {
    if (assistantMode && (mapping.item || mapping.lot || mapping.exp)) {
      generateRegexFromMapping();
    }
  }, [mapping, assistantMode]);

  const handleCharClick = (idx: number) => {
    if (!selection) {
      setSelection({ start: idx, end: idx });
    } else if (selection.start === selection.end && idx !== selection.start) {
      // Set end point
      const start = Math.min(selection.start, idx);
      const end = Math.max(selection.start, idx);
      setSelection({ start, end });
    } else {
      // Reset
      setSelection({ start: idx, end: idx });
    }
  };

  const applySelection = (type: 'item' | 'lot' | 'exp') => {
    if (!selection) return;
    setMapping(prev => ({ ...prev, [type]: [selection.start, selection.end] }));
    setSelection(null);
  };

  const clearAssistant = () => {
    setMapping({});
    setSelection(null);
    setRegexPattern('');
    setItemIdGroup('');
    setLotNoGroup('');
    setExpDateGroup('');
  };

  const loadPatterns = async () => {
    try {
      const data = await apiClient.getBarcodePatterns();
      setPatterns(data);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const handleScan = (text: string) => {
    setShowScanner(false);
    setTestString(text);
  };

  const checkGS1Format = (text: string) => {
    const cleanText = text.trim().replace(/^\][a-zA-Z0-9]{2}/, "").replace(/[()]/g, "").replace(/\s/g, "");
    // Check if it has GTIN (01 + 14 digits)
    if (cleanText.match(/01(\d{14})/)) {
      return true;
    }
    return false;
  };

  const runTest = () => {
    if (!regexPattern || !testString) return;

    setIsGS1Warning(checkGS1Format(testString));

    try {
      const regex = new RegExp(regexPattern);
      const match = testString.match(regex);
      if (match) {
        setTestResult({
          match: true,
          item: itemIdGroup ? match[Number(itemIdGroup)] : undefined,
          lot: lotNoGroup ? match[Number(lotNoGroup)] : undefined,
          exp: expDateGroup ? match[Number(expDateGroup)] : undefined
        });
      } else {
        setTestResult({ match: false });
      }
    } catch (e) {
      setTestResult({ match: false });
    }
  };

  useEffect(() => {
    if (regexPattern && testString) {
      runTest();
    }
  }, [regexPattern, testString, itemIdGroup, lotNoGroup, expDateGroup]);

  const handleSave = async () => {
    if (!name || !regexPattern) return alert("กรุณาระบุชื่อและ Regex Pattern");
    setSaving(true);
    try {
      await apiClient.createBarcodePattern({
        name,
        regex_pattern: regexPattern,
        item_id_group: itemIdGroup ? Number(itemIdGroup) : null,
        lot_no_group: lotNoGroup ? Number(lotNoGroup) : null,
        exp_date_group: expDateGroup ? Number(expDateGroup) : null,
      });
      setName('');
      setRegexPattern('');
      setItemIdGroup('');
      setLotNoGroup('');
      setExpDateGroup('');
      setTestString('');
      setTestResult(null);
      loadPatterns();
    } catch (e: any) {
      alert("Error: " + (e.response?.data?.error || e.message));
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (id: number) => {
    if (!confirm('ยืนยันการลบรูปแบบนี้?')) return;
    try {
      await apiClient.deleteBarcodePattern(id);
      loadPatterns();
    } catch (e) {
      alert("Error deleting");
    }
  };

  if (loading) return <div className="p-8 text-center">Loading...</div>;

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in pb-12">
      <div className="flex items-center justify-between">
        <h1 className="text-3xl font-bold text-gray-900">ตั้งค่า Barcode/QR Code (Smart Parser)</h1>
      </div>

      <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm space-y-6">
        <h2 className="text-xl font-bold flex items-center gap-2">
          <Plus className="text-blue-600" />
          สอนระบบอ่านบาร์โค้ดใหม่
        </h2>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-4">
            <div className="flex items-center gap-2 p-3 bg-blue-50 rounded-xl border border-blue-100">
              <input 
                type="checkbox" 
                id="assistant" 
                checked={assistantMode} 
                onChange={e => setAssistantMode(e.target.checked)} 
                className="w-4 h-4 accent-blue-600"
              />
              <label htmlFor="assistant" className="text-sm font-bold text-blue-700 cursor-pointer">เปิดโหมดผู้ช่วย (Assistant Mode)</label>
            </div>

            <div>
              <label className="block text-sm font-bold text-gray-700 mb-1">ชื่อรูปแบบ (เช่น Roche Custom)</label>
              <input type="text" value={name} onChange={e => setName(e.target.value)} className="w-full border rounded-xl px-4 py-2" placeholder="ชื่อรูปแบบ" />
            </div>

            <div>
              <label className="block text-sm font-bold text-gray-700 mb-1">Regular Expression (Regex)</label>
              <input type="text" value={regexPattern} onChange={e => setRegexPattern(e.target.value)} className={`w-full border rounded-xl px-4 py-2 font-mono ${assistantMode ? 'bg-gray-50' : ''}`} placeholder="^(.{10})(.{6})(.{8})$" readOnly={assistantMode} />
              {assistantMode && <p className="text-[10px] text-blue-600 mt-1 font-bold">* Regex จะถูกสร้างอัตโนมัติจากโหมดผู้ช่วย</p>}
            </div>

            <div className="grid grid-cols-3 gap-2">
              <div>
                <label className="block text-xs font-bold text-gray-700 mb-1">Item ID Group</label>
                <input type="number" value={itemIdGroup} onChange={e => setItemIdGroup(e.target.value ? Number(e.target.value) : '')} className={`w-full border rounded-xl px-4 py-2 ${assistantMode ? 'bg-gray-50' : ''}`} placeholder="เช่น 1" readOnly={assistantMode} />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-700 mb-1">Lot No Group</label>
                <input type="number" value={lotNoGroup} onChange={e => setLotNoGroup(e.target.value ? Number(e.target.value) : '')} className={`w-full border rounded-xl px-4 py-2 ${assistantMode ? 'bg-gray-50' : ''}`} placeholder="เช่น 2" readOnly={assistantMode} />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-700 mb-1">Exp Date Group</label>
                <input type="number" value={expDateGroup} onChange={e => setExpDateGroup(e.target.value ? Number(e.target.value) : '')} className={`w-full border rounded-xl px-4 py-2 ${assistantMode ? 'bg-gray-50' : ''}`} placeholder="เช่น 3" readOnly={assistantMode} />
              </div>
            </div>
          </div>

          <div className="space-y-4 bg-gray-50 p-4 rounded-2xl border border-gray-100">
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-1 flex items-center justify-between">
                1. แสกนหรือวางบาร์โค้ดที่นี่
                <button onClick={() => setShowScanner(true)} className="text-xs bg-blue-100 text-blue-700 px-2 py-1 rounded flex items-center gap-1 hover:bg-blue-200">
                  <Camera size={14} /> แสกนทดสอบ
                </button>
              </label>
              <input type="text" value={testString} onChange={e => setTestString(e.target.value)} className="w-full border rounded-xl px-4 py-2 font-mono" placeholder="วางบาร์โค้ดที่นี่เพื่อทดสอบ" />
            </div>

            {assistantMode && testString && (
              <div className="bg-white p-4 rounded-xl border border-blue-200 space-y-4 shadow-sm">
                <div className="text-[11px] font-bold text-blue-600 uppercase tracking-wider">2. เลือกช่วงตัวอักษรที่ต้องการ</div>
                <div className="flex flex-wrap gap-1 font-mono text-sm leading-none bg-gray-50 p-2 rounded-lg border border-gray-100 select-none">
                  {testString.split('').map((char, idx) => {
                    const isSelected = selection && idx >= selection.start && idx <= selection.end;
                    const isItem = mapping.item && idx >= mapping.item[0] && idx <= mapping.item[1];
                    const isLot = mapping.lot && idx >= mapping.lot[0] && idx <= mapping.lot[1];
                    const isExp = mapping.exp && idx >= mapping.exp[0] && idx <= mapping.exp[1];

                    let bgColor = 'bg-white';
                    let textColor = 'text-gray-600';
                    let borderColor = 'border-gray-200';

                    if (isSelected) { bgColor = 'bg-blue-600'; textColor = 'text-white'; borderColor = 'border-blue-700'; }
                    else if (isItem) { bgColor = 'bg-green-100'; textColor = 'text-green-700'; borderColor = 'border-green-300'; }
                    else if (isLot) { bgColor = 'bg-purple-100'; textColor = 'text-purple-700'; borderColor = 'border-purple-300'; }
                    else if (isExp) { bgColor = 'bg-orange-100'; textColor = 'text-orange-700'; borderColor = 'border-orange-300'; }

                    return (
                      <span 
                        key={idx} 
                        onClick={() => handleCharClick(idx)}
                        className={`cursor-pointer w-6 h-8 flex items-center justify-center rounded border transition-all ${bgColor} ${textColor} ${borderColor} hover:scale-105 active:scale-95`}
                      >
                        {char}
                      </span>
                    );
                  })}
                </div>

                <div className="text-[11px] font-bold text-blue-600 uppercase tracking-wider">3. กำหนดประเภท</div>
                <div className="grid grid-cols-3 gap-2">
                  <button 
                    onClick={() => applySelection('item')} 
                    disabled={!selection}
                    className="px-2 py-2 bg-green-600 text-white rounded-lg text-[10px] font-bold disabled:opacity-30 hover:bg-green-700"
                  >
                    เป็น Item ID
                  </button>
                  <button 
                    onClick={() => applySelection('lot')} 
                    disabled={!selection}
                    className="px-2 py-2 bg-purple-600 text-white rounded-lg text-[10px] font-bold disabled:opacity-30 hover:bg-purple-700"
                  >
                    เป็น Lot No
                  </button>
                  <button 
                    onClick={() => applySelection('exp')} 
                    disabled={!selection}
                    className="px-2 py-2 bg-orange-600 text-white rounded-lg text-[10px] font-bold disabled:opacity-30 hover:bg-orange-700"
                  >
                    เป็น Exp Date
                  </button>
                </div>
                <button 
                  onClick={clearAssistant} 
                  className="w-full py-1 text-[10px] font-bold text-gray-400 hover:text-red-500 transition-colors"
                >
                  ล้างการเลือกทั้งหมด
                </button>
              </div>
            )}

            {!assistantMode && testString && regexPattern && testResult && (
              <div className={`p-4 rounded-xl border ${testResult.match ? 'bg-green-50 border-green-200' : 'bg-red-50 border-red-200'}`}>
                {isGS1Warning && (
                  <div className="mb-4 p-3 bg-amber-50 text-amber-800 border border-amber-200 rounded-lg text-sm flex items-start gap-2">
                    <AlertCircle className="shrink-0 mt-0.5" size={16} />
                    <div>
                      <strong>แจ้งเตือนความเสี่ยง:</strong> บาร์โค้ดนี้ดูเหมือนจะใช้มาตรฐาน GS1 อยู่แล้ว (ระบบเดิมอ่านได้) 
                      การสอนรูปแบบใหม่ทับซ้อนลงไปอาจทำให้ระบบดึงข้อมูลผิดพลาด แนะนำให้ใช้บาร์โค้ดที่ระบบเดิมอ่านไม่ได้จริงๆ ครับ
                    </div>
                  </div>
                )}

                {testResult.match ? (
                  <div className="space-y-2">
                    <div className="flex items-center gap-2 text-green-700 font-bold mb-2">
                      <CheckCircle size={18} /> Match Success!
                    </div>
                    <div className="text-sm"><strong>Item ID:</strong> {testResult.item || '-'}</div>
                    <div className="text-sm"><strong>Lot No:</strong> {testResult.lot || '-'}</div>
                    <div className="text-sm"><strong>Exp Date:</strong> {testResult.exp || '-'}</div>
                  </div>
                ) : (
                  <div className="text-red-700 font-bold">❌ ไม่ตรงกับ Regex Pattern</div>
                )}
              </div>
            )}
          </div>
        </div>

        <div className="flex justify-end">
          <button onClick={handleSave} disabled={saving || !name || !regexPattern} className="bg-blue-600 text-white px-6 py-2 rounded-xl font-bold flex items-center gap-2 disabled:opacity-50">
            {saving ? <Loader2 className="animate-spin" size={18} /> : <Save size={18} />} บันทึกรูปแบบ
          </button>
        </div>
      </div>

      <div className="space-y-4">
        <h2 className="text-xl font-bold">รูปแบบที่เรียนรู้แล้ว ({patterns.length})</h2>
        <div className="grid gap-4">
          {patterns.map(p => (
            <div key={p.id} className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm flex items-center justify-between">
              <div>
                <h3 className="font-bold text-gray-900">{p.name}</h3>
                <code className="text-sm text-pink-600 bg-pink-50 px-2 py-0.5 rounded">{p.regex_pattern}</code>
                <div className="flex gap-4 mt-2 text-xs text-gray-500">
                  <span>Item Group: {p.item_id_group || '-'}</span>
                  <span>Lot Group: {p.lot_no_group || '-'}</span>
                  <span>Exp Group: {p.exp_date_group || '-'}</span>
                </div>
              </div>
              <button onClick={() => handleDelete(p.id)} className="text-gray-400 hover:text-red-500 p-2">
                <Trash2 size={20} />
              </button>
            </div>
          ))}
          {patterns.length === 0 && (
            <div className="text-center p-8 text-gray-400 bg-gray-50 rounded-2xl">ยังไม่มีรูปแบบที่บันทึกไว้</div>
          )}
        </div>
      </div>

      {showScanner && (
        <QRScanner onScan={handleScan} onClose={() => setShowScanner(false)} />
      )}
    </div>
  );
}

